#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <time.h>
#include <math.h>
#include <getopt.h>
#include <chrono>
#include "reference.h"

#define D_FACTOR (0.85f)
#ifndef BLOCK_SIZE
#define BLOCK_SIZE 256
#endif

const int max_iter = 1000;
const float threshold= 1e-16f;

// CUDA Kernel for the map step
__global__ void map_kernel(const int *pages, const float *page_ranks, float *maps, 
                           const unsigned int *noutlinks, int n) {
    int i = blockIdx.x * blockDim.x + threadIdx.x;
    if (i < n) {
        float outbound_rank = page_ranks[i] / (float)noutlinks[i];
        for (int j = 0; j < n; ++j) {
            maps[(size_t)i * n + j] = pages[(size_t)i * n + j] * outbound_rank;
        }
    }
}

// CUDA Kernel for the reduce step
__global__ void reduce_kernel(float *page_ranks, const float *maps, int n, float *diffs) {
    int j = blockIdx.x * blockDim.x + threadIdx.x;
    if (j < n) {
        float old_rank = page_ranks[j];
        float new_rank = 0.0f;
        for (int i = 0; i < n; ++i) {
            new_rank += maps[(size_t)i * n + j];
        }
        new_rank = ((1.f - D_FACTOR) / n) + (D_FACTOR * new_rank);
        float diff = fabsf(new_rank - old_rank);
        if (diff > diffs[j]) {
            diffs[j] = diff;
        }
        page_ranks[j] = new_rank;
    }
}

int *random_pages(int n, unsigned int *noutlinks, int divisor){
  int i, j, k;
  int *pages = (int*) malloc((size_t)n * n * sizeof(int)); 

  if (divisor <= 0) {
    fprintf(stderr, "ERROR: Invalid divisor '%d' for random initialization, divisor should be greater or equal to 1\n", divisor);
    exit(1);
  }

  for(i=0; i<n; ++i){
    noutlinks[i] = 0;
    for(j=0; j<n; ++j){
      if(i!=j && (abs(rand())%divisor == 0)){
        pages[(size_t)i*n+j] = 1;
        noutlinks[i] += 1;
      }
    }


    if(noutlinks[i] == 0){
      do { k = abs(rand()) % n; } while ( k == i);
      pages[(size_t)i*n + k] = 1;
      noutlinks[i] = 1;
    }
  }
  return pages;
}

void init_array(float *a, int n, float val){
  int i;
  for(i=0; i<n; ++i){
    a[i] = val;
  }
}

void usage(char *argv[]){
  fprintf(stderr, "Usage: %s [-n number of pages] [-i max iterations]"
      " [-t threshold] [-q divsor for zero density]\n", argv[0]);
}

static struct option size_opts[] =
{

  {"number of pages", 1, NULL, 'n'},
  {"max number of iterations", 1, NULL, 'i'},
  {"minimum threshold", 1, NULL, 't'},
  {"divisor for zero density", 1, NULL, 'q'},
  { 0, 0, 0}
};

float maximum_dif(float *difs, int n){
  int i;
  float max = 0.0f;
  for(i=0; i<n; ++i){
    max = difs[i] > max ? difs[i] : max;
  }
  return max;
}

int main(int argc, char *argv[]) {
  int *pages;
  float *maps;
  float *page_ranks;
  unsigned int *noutlinks;
  int t;
  float max_diff, max_diff_ref;

  int i = 0;
  int j;
  int n = 1000;
  int iter = max_iter;
  float thresh = threshold;
  int divisor = 2;

  int opt, opt_index = 0;
  while((opt = getopt_long(argc, argv, "::n:i:t:q:", size_opts, &opt_index)) != -1){
    switch(opt){
      case 'n':
        n = atoi(optarg);
        break;
      case 'i':
        iter = atoi(optarg);
        break;
      case 't':
        thresh = atof(optarg);
        break;
      case 'q':
        divisor = atoi(optarg);
        break;
      default:
        usage(argv);
        exit(EXIT_FAILURE);
    }
  }

  size_t rank_size = (size_t)n * sizeof(float);
  size_t map_size = (size_t)n * n * sizeof(float);

  size_t link_size = (size_t)n * sizeof(unsigned int);

  page_ranks = (float*)malloc(rank_size);
  maps = (float*)malloc(map_size);
  noutlinks = (unsigned int*)malloc(link_size);

  max_diff=max_diff_ref=99.0f;

  for (i=0; i<n; ++i) {
    noutlinks[i] = 0;
  }
  pages = random_pages(n,noutlinks,divisor);
  init_array(page_ranks, n, 1.0f / (float) n);

  float *diffs;
  diffs  = (float*) malloc(rank_size);
  memset(diffs, 0, rank_size);

  size_t block_size  = n < BLOCK_SIZE ? n : BLOCK_SIZE;
  int num_blocks = (n + block_size - 1) / block_size;

  double ktime = 0.0;

  // Allocate CUDA memory
  int *d_pages;
  float *d_maps;
  float *d_page_ranks;
  unsigned int *d_noutlinks;
  float *d_diffs;

  cudaMalloc(&d_pages, (size_t)n * n * sizeof(int));
  cudaMalloc(&d_maps, (size_t)n * n * sizeof(float));
  cudaMalloc(&d_page_ranks, rank_size);
  cudaMalloc(&d_noutlinks, link_size);
  cudaMalloc(&d_diffs, rank_size);

  // Copy initial data to device
  cudaMemcpy(d_pages, pages, (size_t)n * n * sizeof(int), cudaMemcpyHostToDevice);
  cudaMemcpy(d_page_ranks, page_ranks, rank_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_noutlinks, noutlinks, link_size, cudaMemcpyHostToDevice);
  cudaMemcpy(d_diffs, diffs, rank_size, cudaMemcpyHostToDevice);

  for (t=1; t<=iter && max_diff>=thresh; ++t) {
    auto start = std::chrono::high_resolution_clock::now();

    // Map step
    map_kernel<<<num_blocks, block_size>>>(d_pages, d_page_ranks, d_maps, d_noutlinks, n);

    // Reset diffs on device before reduce (since reduce accumulates max)
    // In the original code, diffs[j] is updated with fmaxf(fabsf(...), diffs[j]).
    // Since diffs is initialized to 0 and we want the max diff of the current iteration,
    // we need to ensure diffs is 0 at the start of each iteration if we are accumulating per iteration.
    // However, looking at the original OpenMP code:
    // diffs is allocated and memset to 0 once before the loop.
    // Inside the loop: diffs[j] = fmaxf(fabsf(new_rank - old_rank), diffs[j]);
    // This implies diffs accumulates the maximum difference seen *ever* for that index across iterations?
    // But then max_diff = maximum_dif(diffs, n) is checked against thresh to stop.
    // And the reference code does: memset(diffs, 0, rank_size) BEFORE the reference loop.
    // Wait, the original OpenMP code does NOT reset diffs inside the loop. 
    // But the reference code DOES reset diffs before its loop.
    // Let's re-read carefully.
    // Original OpenMP: diffs allocated, memset 0. Loop t=1..iter. Inside: diffs[j] = fmaxf(..., diffs[j]).
    // This means diffs[j] holds the max difference for index j over ALL iterations so far.
    // Then max_diff is the global max over all j and all iterations so far.
    // This seems odd for convergence check. Usually you check max diff of current iteration.
    // Let's look at the reference code provided in infrastructure context:
    // memset(diffs, 0, rank_size); THEN for t=1..iter { map_ref; reduce_ref; max_diff_ref = maximum_dif(diffs, n); }
    // The reference code resets diffs BEFORE the loop, but NOT inside the loop.
    // So the reference code also accumulates the max diff over all iterations.
    // So the CUDA code must do the same. We only reset diffs once before the loop (already done by cudaMemcpy from host which is 0).
    // But wait, if we don't reset diffs inside the loop, then diffs[j] will keep the max from previous iterations.
    // That matches the original OpenMP code logic.

    // Reduce step
    reduce_kernel<<<num_blocks, block_size>>>(d_page_ranks, d_maps, n, d_diffs);

    cudaDeviceSynchronize();

    auto end = std::chrono::high_resolution_clock::now();
    ktime += std::chrono::duration_cast<std::chrono::duration<double> >(end - start).count();

    // Copy diffs back to host to compute max_diff
    cudaMemcpy(diffs, d_diffs, rank_size, cudaMemcpyDeviceToHost);
    max_diff = maximum_dif(diffs, n);
  }

  fprintf(stderr, "Max difference %f is reached at iteration %d\n", max_diff, t);
  printf("\"Options\": \"-n %d -i %d -t %f\". Total kernel execution time: %lf (s)\n",
         n, iter, thresh, ktime);

  // Free CUDA memory
  cudaFree(d_pages);
  cudaFree(d_maps);
  cudaFree(d_page_ranks);
  cudaFree(d_noutlinks);
  cudaFree(d_diffs);

  // Reference calculation
  memset(diffs, 0, rank_size);
  for (t=1; t<=iter && max_diff_ref>=thresh; ++t) {
    map_ref(pages, page_ranks, maps, noutlinks, n);
    reduce_ref(page_ranks, maps, n, diffs);
    max_diff_ref = maximum_dif(diffs, n);
  }
  bool ok = fabsf(max_diff - max_diff_ref) < 1e-3f;
  printf("%s\n", ok ? "PASS" : "FAIL");

  free(pages);
  free(maps);
  free(page_ranks);
  free(noutlinks);
  free(diffs);
  return 0;
}
